353	  /**
354	   * List issues from the index with optional filters.
355	   *
356	   * Returns entries sorted by: priority ASC → impact score DESC → id ASC.
357	   * Impact score is the count of active issues this issue blocks.
358	   *
359	   * @param params - Optional filter parameters
360	   * @param params.status - Filter by status; "open" = all non-closed, "closed" = closed only
361	   * @param params.assignee - Filter by assignee name
362	   * @param params.tags - AND filter — issue must have ALL specified tags
363	   * @param params.parentId - Filter by parent ID; null = top-level issues only
364	   * @returns Array of index entries matching the filters
365	   * @throws {TrackgenticError} NOT_INITIALIZED if no `.trackgentic/` directory
366	   * @throws {TrackgenticError} TOKEN_REQUIRED if auth mode is strict and no token provided
367	   *
368	   * @example
369	   * ```typescript
370	   * const openUrgent = await tracker.list({
371	   *   status: "open",
372	   *   tags: ["urgent"],
373	   *   parentId: null,
374	   * });
375	   * ```
376	   */
377	  async list(params?: ListParams): Promise<ListResult> {
378	    const trackerDir = resolveTrackerDir(this.cwd);
379	    if (!trackerDir) {
380	      throw new TrackgenticError(
381	        ErrorCodes.NOT_INITIALIZED.result,
382	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
383	        ErrorCodes.NOT_INITIALIZED.exitCode,
384	      );
385	    }
386	
387	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
388	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
389	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
390	    if (authResult instanceof TrackgenticError) {
391	      throw authResult;
392	    }
393	
394	    const index = await readIndex(trackerDir);
395	
396	    // Determine source arrays based on params.status
397	    let entries: IndexEntry[];
398	    if (params?.status === "closed") {
399	      entries = index.closed;
400	    } else if (params?.status === "open") {
401	      entries = index.open;
402	    } else if (params?.status) {
403	      entries = index.open;
404	    } else {
405	      entries = [...index.open, ...index.closed];
406	    }
407	
408	    // Filter in memory
409	    let filtered = entries;
410	
411	    if (params?.status && params.status !== "open" && params.status !== "closed") {
412	      filtered = filtered.filter((e) => e.status === params.status);
413	    }
414	
415	    if (params?.assignee) {
416	      filtered = filtered.filter((e) => e.assignee === params.assignee);
417	    }
418	
419	    if (params?.tags && params.tags.length > 0) {
420	      filtered = filtered.filter((e) => params.tags?.every((tag) => e.tags.includes(tag)));
421	    }
422	
423	    if (params?.parentId !== undefined) {
424	      if (params.parentId === null) {
425	        filtered = filtered.filter((e) => e.parentId === null);
426	      } else {
427	        filtered = filtered.filter((e) => e.parentId === params.parentId);
428	      }
429	    }
430	
431	    // Read dependencies once for impact score
432	    let deps: DependenciesFile | null = null;
433	
434	    // Sort: priority ASC → impact DESC → id ASC
435	    filtered.sort((a, b) => {
436	      if (a.priority !== b.priority) return a.priority - b.priority;
437	      // Lazy-load deps only once for sorting
438	      if (!deps) {
439	        deps = readDependenciesSync(trackerDir);
440	      }
441	      const impactA = getImpactScore(deps, a.id);
442	      const impactB = getImpactScore(deps, b.id);
443	      if (impactA !== impactB) return impactB - impactA;
444	      return a.id.localeCompare(b.id);
445	    });
446	
447	    return filtered;
448	  }
