592	  /**
593	   * Update an existing issue.
594	   *
595	   * Appends an update event to the issue file, recomputes state, and updates the index.
596	   * Handles hierarchy side effects: downward cascade (auto-close done children when parent
597	   * closes), upward promotion (promote parent when child advances past it), and reparenting
598	   * validation. Also auto-resolves active blockages when the issue transitions to done/closed.
599	   *
600	   * @param id - The issue ID to update
601	   * @param params - Update parameters (at least one field required besides author)
602	   * @param params.title - New title
603	   * @param params.description - New description
604	   * @param params.status - New status
605	   * @param params.assignee - New assignee, or null to clear
606	   * @param params.tags - New tags (replaces existing)
607	   * @param params.priority - New priority (1-5)
608	   * @param params.parentId - New parent ID, or null to detach
609	   * @param params.author - Override author (resolved by auth layer if not provided)
610	   * @returns `{ result: "OK" }` on success, or a TrackgenticError on auth failure
611	   * @throws {TrackgenticError} NOT_INITIALIZED if no `.trackgentic/` directory
612	   * @throws {TrackgenticError} INVALID_PARAMS if no fields provided besides author
613	   * @throws {TrackgenticError} NOT_FOUND if issue ID is not in the index
614	   * @throws {TrackgenticError} ISSUE_MISSING if index entry exists but file is missing
615	   * @throws {TrackgenticError} HIERARCHY_CONSTRAINT if status change violates parent/child rules
616	   *
617	   * @example
618	   * ```typescript
619	   * await tracker.update("abc123def4", { status: "in-progress", priority: 2 });
620	   * ```
621	   */
622	  async update(id: IssueId, params: UpdateParams): Promise<UpdateResult> {
623	    const trackerDir = resolveTrackerDir(this.cwd);
624	    if (!trackerDir) {
625	      throw new TrackgenticError(
626	        ErrorCodes.NOT_INITIALIZED.result,
627	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
628	        ErrorCodes.NOT_INITIALIZED.exitCode,
629	      );
630	    }
