634	      params.title !== undefined ||
635	      params.description !== undefined ||
636	      params.status !== undefined ||
637	      params.assignee !== undefined ||
638	      params.tags !== undefined ||
639	      params.priority !== undefined ||
640	      params.parentId !== undefined;
