650	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
651	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
652	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
653	    if (authResult instanceof TrackgenticError) return authResult;
654	    const author = params.author ?? authResult.author;
655	
656	    const index = await readIndex(trackerDir);
657	    const entry = findEntry(index, id);
658	    if (!entry) {
659	      throw new TrackgenticError(
660	        ErrorCodes.NOT_FOUND.result,
661	        `Issue \`${id}\` not found in index.`,
662	        ErrorCodes.NOT_FOUND.exitCode,
663	      );
664	    }
665	
666	    const issueFilePath = join(trackerDir, entry.path);
667	    if (!existsSync(issueFilePath)) {
668	      throw new TrackgenticError(
669	        ErrorCodes.ISSUE_MISSING.result,
670	        `Issue file for \`${id}\` is missing.`,
671	        ErrorCodes.ISSUE_MISSING.exitCode,
672	      );
673	    }
674	
675	    // Save old values for hierarchy handling
676	    const oldStatus = entry.status;
677	    const oldParentId = entry.parentId;
678	
679	    // ── Hierarchy validation (before any state changes) ────────────
680	
681	    // Validate downward constraints for status change
682	    if (params.status !== undefined && params.status !== oldStatus) {
683	      if (params.status === "done" || params.status === "closed") {
684	        const childIds = getChildren(index, id);
685	        const childEntries = childIds
686	          .map((cid) => findEntry(index, cid))
687	          .filter((e): e is IndexEntry => e !== null);
688	        const validationError = validateParentStatusChange(index, childEntries, params.status);
689	        if (validationError) {
690	          throw new TrackgenticError(
691	            ErrorCodes.HIERARCHY_CONSTRAINT.result,
692	            validationError,
693	            ErrorCodes.HIERARCHY_CONSTRAINT.exitCode,
694	          );
695	        }
696	      }
697	    }
698	
699	    // Validate reparenting constraints
700	    if (params.parentId !== undefined && params.parentId !== oldParentId) {
701	      if (params.parentId !== null) {
702	        const newParentEntry = findEntry(index, params.parentId);
703	        if (!newParentEntry) {
704	          throw new TrackgenticError(
705	            ErrorCodes.NOT_FOUND.result,
706	            `Parent issue \`${params.parentId}\` not found in index.`,
707	            ErrorCodes.NOT_FOUND.exitCode,
708	          );
709	        }
710	        const validationError = validateNewChild(newParentEntry);
711	        if (validationError) {
712	          throw new TrackgenticError(
713	            ErrorCodes.HIERARCHY_CONSTRAINT.result,
714	            validationError,
715	            ErrorCodes.HIERARCHY_CONSTRAINT.exitCode,
716	          );
717	        }
718	      }
