803	      }
804	
805	      // Upward promotion: promote parent if child advanced past it
806	      const currentParentId = computed.parentId;
807	      if (currentParentId) {
808	        const parentEntry = findEntry(updatedIndex, currentParentId);
809	        if (parentEntry && isStatusAfter(params.status, parentEntry.status)) {
810	          const promotions = computeUpwardPromotions(
811	            updatedIndex,
812	            parentEntry,
813	            params.status,
814	            (iid) => findEntry(updatedIndex, iid),
815	          );
816	          for (const promo of promotions) {
817	            const promoEntry = findEntry(updatedIndex, promo.issueId);
818	            if (promoEntry && promo.event.type === "update" && promo.event.content.status) {
819	              await appendEvent(join(trackerDir, promoEntry.path), promo.event);
820	              updatedIndex = updateEntry(updatedIndex, promo.issueId, {
821	                status: promo.event.content.status,
822	              });
823	            }
824	          }
825	        }
826	      }
827	    }
828	
829	    await writeIndex(trackerDir, updatedIndex);
830	
831	    // ── Auto-resolution: resolve active blockages when issue → done/closed ──
832	    if (params.status !== undefined && params.status !== oldStatus) {
833	      if (params.status === "done" || params.status === "closed") {
834	        const deps = await readDependencies(trackerDir);
835	        const activeBlocks = (deps.blocks[id] ?? []).filter((e) => e.status === "active");
836	
837	        if (activeBlocks.length > 0) {
838	          let updatedDeps = deps;
839	          for (const entry of activeBlocks) {
840	            updatedDeps = resolveBlockage(updatedDeps, entry.blockedId, entry.blockerId);
841	
842	            const blockedEntry = findEntry(updatedIndex, entry.blockedId);
843	            if (blockedEntry) {
844	              const now = new Date().toISOString();
845	              const resolveEvent: Event = {
846	                type: "blockage-resolved",
847	                timestamp: now,
848	                author: "system",
