1354	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
1355	    if (authResult instanceof TrackgenticError) return authResult;
1356	    const author = params.author ?? authResult.author;
1357	
1358	    const index = await readIndex(trackerDir);
1359	
1360	    if (!findEntry(index, blockedId)) {
