1408	   *
1409	   * @example
1410	   * ```typescript
1411	   * await tracker.blockagesDelete("blocked001", { blockerIds: ["blocker001"] });
1412	   * ```
1413	   */
1414	  async blockagesDelete(
1415	    blockedId: IssueId,
1416	    params: BlockagesDeleteParams,
1417	  ): Promise<BlockagesDeleteResult> {
1418	    const trackerDir = resolveTrackerDir(this.cwd);
1419	    if (!trackerDir) {
