1539	   * ```typescript
1540	   * const result = await tracker.usersRegister("Alice");
1541	   * if ("token" in result) console.log("Token:", result.token);
1542	   * ```
1543	   */
1544	  async usersRegister(name: string): Promise<UsersRegisterResult> {
1545	    const trackerDir = resolveTrackerDir(this.cwd);
1546	    if (!trackerDir) {
1547	      throw new TrackgenticError(
1548	        ErrorCodes.NOT_INITIALIZED.result,
1549	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
1550	        ErrorCodes.NOT_INITIALIZED.exitCode,
1551	      );
1552	    }
1553	
1554	    const lowerName = name.toLowerCase();
1555	
1556	    // Reject reserved name
1557	    if (lowerName === "anonymous") {
