1574	    const token = generateToken();
1575	    const newUser: UserEntry = {
1576	      name: lowerName,
1577	      token,
1578	      registeredAt: new Date().toISOString(),
1579	    };
1580	
1581	    users.users.push(newUser);
1582	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
1583	
1584	    return { result: "OK", name: lowerName, token };
1585	  }
1586	
1587	  /**
1588	   * List all registered users with tokens stripped.
1589	   *
1590	   * Returns public user info (name and registration date) without exposing tokens.
1591	   * Auth requirements depend on the configured mode (read operation).
1592	   *
1593	   * @returns Array of user info objects (no tokens)
1594	   * @throws {TrackgenticError} NOT_INITIALIZED if no `.trackgentic/` directory
1595	   * @throws {TrackgenticError} TOKEN_REQUIRED if auth mode is strict and no token provided
1596	   *
1597	   * @example
