1603	  async usersList(): Promise<UsersListResult> {
1604	    const trackerDir = resolveTrackerDir(this.cwd);
1605	    if (!trackerDir) {
1606	      throw new TrackgenticError(
1607	        ErrorCodes.NOT_INITIALIZED.result,
1608	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
1609	        ErrorCodes.NOT_INITIALIZED.exitCode,
1610	      );
1611	    }
1612	
1613	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
1614	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
1615	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
1616	    if (authResult instanceof TrackgenticError) {
1617	      throw authResult;
1618	    }
1619	
1620	    return users.users.map((u) => ({
1621	      name: u.name,
1622	      registeredAt: u.registeredAt,
1623	    }));
1624	  }
1625	
1626	  /**
1627	   * Revoke (remove) a user from the system.
1628	   *
1629	   * Removes the user and their token from the users file.
1630	   * Requires authentication (write operation).
1631	   *
1632	   * @param name - The user name to revoke (case-insensitive)
1633	   * @returns `{ result: "OK" }` on success, or `{ result: "USER_NOT_FOUND", message }`
1634	   * @throws {TrackgenticError} NOT_INITIALIZED if no `.trackgentic/` directory
1635	   * @throws {TrackgenticError} TOKEN_REQUIRED if no token provided in auth-required mode
1636	   *
1637	   * @example
1638	   * ```typescript
1639	   * const result = await tracker.usersRevoke("alice");
1640	   * if (result.result === "OK") console.log("User revoked.");
1641	   * ```
1642	   */
1643	  async usersRevoke(name: string): Promise<UsersRevokeResult> {
1644	    const trackerDir = resolveTrackerDir(this.cwd);
1645	    if (!trackerDir) {
1646	      throw new TrackgenticError(
1647	        ErrorCodes.NOT_INITIALIZED.result,
1648	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
1649	        ErrorCodes.NOT_INITIALIZED.exitCode,
1650	      );
1651	    }
1652	
1653	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
1654	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
1655	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
1656	    if (authResult instanceof TrackgenticError) {
1657	      throw authResult;
1658	    }
1659	
1660	    const lowerName = name.toLowerCase();
1661	    const userIndex = users.users.findIndex((u) => u.name === lowerName);
1662	    if (userIndex === -1) {
1663	      return {
1664	        result: "USER_NOT_FOUND",
1665	        message: `User "${lowerName}" not found.`,
1666	      };
1667	    }
1668	
1669	    users.users.splice(userIndex, 1);
1670	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
1671	
1672	    return { result: "OK" };
1673	  }
1674	
1675	  /**
1676	   * Regenerate a user's authentication token.
1677	   *
1678	   * Self-service only — the authenticated caller must be the target user.
1679	   * Generates a new token and replaces the old one in the users file.
1680	   *
1681	   * @param name - The user name whose token to regenerate (case-insensitive)
1682	   * @returns `{ result: "OK", name, token }` with the new token, or an error result
1683	   * @throws {TrackgenticError} NOT_INITIALIZED if no `.trackgentic/` directory
1684	   * @throws {TrackgenticError} TOKEN_REQUIRED if no token provided
1685	   *
1686	   * @example
1687	   * ```typescript
1688	   * const result = await tracker.usersRegenerate("alice");
1689	   * if ("token" in result) console.log("New token:", result.token);
1690	   * ```
1691	   */
1692	  async usersRegenerate(name: string): Promise<UsersRegenerateResult> {
1693	    const trackerDir = resolveTrackerDir(this.cwd);
1694	    if (!trackerDir) {
1695	      throw new TrackgenticError(
1696	        ErrorCodes.NOT_INITIALIZED.result,
1697	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
1698	        ErrorCodes.NOT_INITIALIZED.exitCode,
1699	      );
1700	    }
1701	
1702	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
1703	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
1704	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
1705	    if (authResult instanceof TrackgenticError) {
1706	      throw authResult;
1707	    }
1708	
1709	    const callerName = authResult.author;
1710	    const lowerName = name.toLowerCase();
1711	
1712	    // Self-service check: caller must be the target user
1713	    if (callerName !== lowerName) {
1714	      return {
1715	        result: "INVALID_TOKEN",
1716	        message: "You can only regenerate your own token.",
1717	      };
1718	    }
1719	
1720	    const user = users.users.find((u) => u.name === lowerName);
1721	    if (!user) {
1722	      return {
1723	        result: "USER_NOT_FOUND",
1724	        message: `User "${lowerName}" not found.`,
1725	      };
1726	    }
1727	
1728	    const newToken = generateToken();
1729	    user.token = newToken;
1730	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
1731	
1732	    return { result: "OK", name: lowerName, token: newToken };
1733	  }
1734	}
