24	  async function runCLI(
25	    ...args: string[]
26	  ): Promise<{ stdout: string; stderr: string; exitCode: number }> {
27	    return runCLIWithEnv({}, ...args);
28	  }
29	
30	  async function runCLIWithEnv(
31	    env: Record<string, string>,
32	    ...args: string[]
33	  ): Promise<{ stdout: string; stderr: string; exitCode: number }> {
34	    const proc = spawn({
35	      cmd: ["bun", "run", BIN_PATH, ...args],
36	      cwd: testDir,
37	      stdout: "pipe",
38	      stderr: "pipe",
39	      env: { ...process.env, ...env },
40	    });
41	
42	    const stdout = await new Response(proc.stdout).text();
43	    const stderr = await new Response(proc.stderr).text();
44	    const exitCode = await proc.exited;
45	
46	    return { stdout, stderr, exitCode };
47	  }
